script:
export const meta = { name: 'camiel-roadmap-light', description: 'Light fan-out to find roadmap docs for Project-Camiel', phases: [{ title: 'Search' }, { title: 'Synthesize' }] };

phase('Search');

const findings = await parallel([
  () => agent(`Look for roadmap, changelog, todo, or project documents in /Volumes/T9/Code/projects/Project-Camiel. Check: ROADMAP.md, TODO.md, CHANGELOG.md, docs/, .claude/, .github/, .gitlab/, and any markdown in the root. Also read package.json version and scripts. Return file paths and key content verbatim.`, { label: 'roadmap-files', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' }),
  () => agent(`In /Volumes/T9/Code/projects/Project-Camiel, run: git branch -a && git tag -l && git log --oneline -20 && git remote -v. Also run: glab project list --mine 2>/dev/null; glab issue list 2>/dev/null; glab milestone list 2>/dev/null. Return all output.`, { label: 'git-context', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' }),
  () => agent(`Check the Next.js app at /Volumes/T9/Code/projects/Project-Camiel for any /roadmap, /changelog, /status, or /blog pages in src/app/. Also check src/components/ for any roadmap-related UI components and public/ for any changelog files. Return paths and content.`, { label: 'ui-pages', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' }),
]);

phase('Synthesize');

const summary = await agent(`You are the synthesizer. Given the findings below, produce a concise roadmap status report for Project-Camiel. 

For each source found, note:
1. Version/stage from package.json or git tags
2. Any planned or in-progress features from docs/branches/commits  
3. Any locked/deferred items
4. Gaps — what's not clear

If no roadmap exists anywhere, say so clearly and suggest how to create one.

--- FINDINGS ---
${findings.map((f, i) => `=== Source ${i + 1} ===\n${f || 'No output'}`).join('\n\n')}
`, { label: 'synthesize', tier: 'medium' });

return { ok: true, findings, summary };
